{
  "customer_summary": {
    "summary": "The frontend of the application is being upgraded to Angular 19. Angular 19 removes the legacy SASS import mechanism and requires the new SASS compiler that is bundled with the Angular Builder (`@angular-devkit/build-angular:application`). Migrating to this compiler is mandatory to keep the build process functional after the framework upgrade. Without the migration the application will fail to compile, future Angular updates will be blocked and users could experience broken UI or missing styles, which would increase maintenance cost and risk of regressions.",
    "impact_level": "medium",
    "is_bug": false,
    "workaround": "",
    "eta_category": "short"
  },
  "developer_context": {
    "big_picture": "The project is a large Angular single‑page application that serves internal users (e.g., employees of the client) and external customers via a web UI. It lives in the **frontend** container and belongs to the **presentation** layer of the overall system architecture. The task is to migrate the SASS compilation step to the new Angular Builder because Angular 19 deprecates the old SASS import strategy. This migration is part of the scheduled Angular 19 upgrade, which is required now to stay on a supported framework version and to avoid build breakage. If the migration is not performed, the next framework upgrade will fail, causing downtime for UI releases and increasing the technical debt of the styling pipeline.",
    "scope_boundary": "IN: Update `angular.json` (or workspace configuration) to use `@angular-devkit/build-angular:application` for SASS, adjust any custom SASS loader settings, verify that all `.scss` files compile, run the full UI test suite (Karma, Playwright) to catch regressions. OUT: Any other Angular version upgrades (e.g., core, router), backend services, database schema changes, or feature development unrelated to the build process.",
    "classification_assessment": "",
    "classification_confidence": -1,
    "affected_components": [
      "AngularBuildConfig (presentation)",
      "StyleCompilation (presentation)",
      "CI/CD Build Pipeline (infrastructure)"
    ],
    "context_boundaries": [
      {
        "category": "technology_constraint",
        "boundary": "Angular 19 no longer supports the legacy SASS import syntax; the project must switch to the SASS compiler provided by `@angular-devkit/build-angular:application`. This drives the need to change the build configuration and may require updating the SASS version used by the project.",
        "severity": "blocking",
        "source_facts": [
          "tech_versions.json: Angular 18-lts",
          "tech_versions.json: Angular CLI 18-lts",
          "ADR: UVZ-09-ADR-003 Frontend Build Strategy SASS Import Deprecation"
        ]
      },
      {
        "category": "testing_constraint",
        "boundary": "The migration can introduce subtle style regressions. All existing unit tests (Karma) and end‑to‑end tests (Playwright) must be executed after the change to ensure the UI renders correctly.",
        "severity": "caution",
        "source_facts": [
          "tech_versions.json: Karma 6.4.3",
          "tech_versions.json: Playwright 1.44.1"
        ]
      },
      {
        "category": "dependency_risk",
        "boundary": "The new builder may depend on a newer version of the `sass` npm package. Verify that the current `sass` version in `package.json` satisfies the builder’s peer‑dependency range to avoid install failures.",
        "severity": "info",
        "source_facts": [
          "dependencies.json: @angular/compiler v18-lts"
        ]
      },
      {
        "category": "workflow_constraint",
        "boundary": "CI/CD pipelines that invoke `ng build` need to be checked for any custom flags that were previously used for the old SASS compiler. Those flags may be obsolete or cause errors with the new builder.",
        "severity": "caution",
        "source_facts": [
          "architecture_overview: 5 containers, 1003 components"
        ]
      }
    ],
    "architecture_notes": "The SASS compilation lives inside the **frontend** container, specifically in the **presentation** layer. The key component is `AngularBuildConfig`, which is defined in `angular.json` and is consumed by the Angular CLI during the build step. This component talks to the **CI/CD pipeline** (infrastructure) that triggers `ng build` and later to the **test harness** (Karma for unit tests, Playwright for e2e). After migration, the `AngularBuildConfig` will point to the `@angular-devkit/build-angular:application` builder, which internally uses the new SASS compiler. No other containers (e.g., backend, data‑access) are affected. The neighboring components are:\n- `StyleCompilation` (processes `.scss` files)\n- `CI/CD Build Pipeline` (executes the build)\n- `Karma` and `Playwright` test runners (validate output).\nDevelopers should locate the `angular.json` file, identify the `architect.build.builder` entry, and replace the legacy builder with the new one, then run the full test suite.",
    "anticipated_questions": [
      {
        "question": "Do I need to update the `sass` npm package version as part of this migration?",
        "answer": "Check the peer‑dependency range of `@angular-devkit/build-angular` (documented in its package.json). If the current `sass` version is outside that range, bump it to a compatible version. Otherwise, no change is required."
      },
      {
        "question": "Will this migration affect existing unit or e2e tests?",
        "answer": "Potentially. The new compiler may produce slightly different CSS output (e.g., ordering, source maps). Run the full Karma and Playwright suites after the change to catch any visual regressions."
      },
      {
        "question": "Are there any CI/CD script changes needed?",
        "answer": "Review the build scripts for custom flags that were specific to the old SASS compiler. Those flags may be removed or replaced. The basic `ng build` command stays the same."
      },
      {
        "question": "Is this migration tied to the Angular version bump, or can it be done independently?",
        "answer": "The new SASS compiler is only available in the Angular 19 builder package. Therefore the migration must be performed as part of the Angular 19 upgrade; doing it earlier would require pulling in a future‑preview version of the builder, which is not recommended."
      },
      {
        "question": "What should I do if the build fails after switching the builder?",
        "answer": "Consult the build error output; common issues are missing peer dependencies (e.g., `sass`) or leftover custom loader configurations in `angular.json`. Adjust the configuration accordingly and re‑run the build."
      }
    ],
    "linked_tasks": [
      "UVZ-09-ADR-003 Frontend Build Strategy SASS Import Deprecation (architectural decision record)",
      "Angular 19 Upgrade Epic (parent epic for this migration)"
    ]
  }
}

